def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 1.5:
            score += (ratio - 1.5) ** 3 * 200
        elif ratio > 1:
            score += (ratio - 1) * 150
        else:
            for power in range(1, 6):
                term = ((-1) ** power) * (ratio ** power) / power
                score += term
            if ratio < 0.3:
                score *= 0.8
            elif 0.3 <= ratio < 0.7:
                score *= (1 + 0.3 * np.sin(capacity / (item + 1)))
            else:
                adjustment = 0
                for k in range(1, 4):
                    adjustment += np.log(k + capacity % (item + 1) + 1) / (k + power)
                score *= (1 + adjustment * 0.1)
        if capacity > 3 * item:
            score -= 0.2 * (capacity - 3 * item)
        if capacity < item:
            for _ in range(3):
                score += np.random.uniform(0, 1)
        if score < 0:
            priorities[i] = max(score, -10)
        else:
            priorities[i] = score
    return priorities
